// State context (now present on each line)
const fulfillmentRaw = String(rows[0]?.Fulfillment || '').toLowerCase().trim();
const address  = String(rows[0]?.Address  || '').trim();
const zone     = String(rows[0]?.Zone     || '').trim();
const phone    = String(rows[0]?.Phone    || '').trim();
const feeInput = Number(rows[0]?.DeliveryFee ?? 0);
const isPickup   = fulfillmentRaw === 'pickup';
const isDelivery = fulfillmentRaw === 'delivery';
const fee        = isPickup ? 0 : (Number.isFinite(feeInput) ? feeInput : 0);

// Lines
const header = pad('🧺 *Your Cart*');
const lines = rows.map(r => {
  const qty   = Number(r.Quantity ?? r.qty ?? 1) || 1;
  const price = Number(r.Price ?? r.price ?? 0)  || 0;
  const name  = String(r.Dish ?? r.name ?? r.SKU ?? '').trim();

  // NEW: prefer saved LineTotal; fall back to qty * price
  const ltRaw = Number(r.LineTotal ?? r.line_total);
  const lineTotal = (Number.isFinite(ltRaw) && ltRaw > 0) ? ltRaw : qty * price;

  // CHANGED: print line total, not unit price
  return pad(`• ${name} x${qty} — ${money(lineTotal)}`);
});

const subtotal = rows.reduce((s, r) => {
  const lt = Number(r.LineTotal ?? r.line_total);
  if (Number.isFinite(lt) && lt > 0) return s + lt;
  const q = Number(r.Quantity ?? r.qty ?? 1) || 1;
  const p = Number(r.Price ?? r.price ?? 0)  || 0;
  return s + q * p;
}, 0);

const fulfillmentLine = isPickup
  ? '🏪 Pickup at counter'
  : (isDelivery
     ? `🚚 Delivery${address ? ` to: ${address}` : ''}${zone ? ` (Zone: ${zone})` : ''}`
     : '— choose delivery or pickup below —');

const meta = [
  pad(`*Fulfillment:* ${fulfillmentLine}`),
  phone ? pad(`*Phone:* ${phone}`) : null
].filter(Boolean);

const foot = [
  pad(`*Subtotal:* ${money(subtotal)}`),
  pad(`*Delivery fee:* ${money(fee)}`),
  pad(`*Total:* ${money(subtotal + fee)}`)
];

const text = [header, '', ...lines, '', ...meta, '', ...foot].join('\n');

// Keyboard
const baseRows = [
  [
    { text: '🧹 Clear', callback_data: 'CART|CLEAR' },
    { text: '🍽️ Continue Shopping', callback_data: 'MENU|REFRESH' }
  ]
];

let keyboard;
if (!isPickup && !isDelivery) {
  keyboard = [
    [
      { text: '🚚 Delivery', callback_data: 'FULFILL|DELIVERY' },
      { text: '🏪 Pickup',   callback_data: 'FULFILL|PICKUP' }
    ],
    ...baseRows
  ];
} else if (isPickup) {
  keyboard = [
    [{ text: '💳 Pay now', callback_data: 'PAY' }],
    [{ text: 'Change to Delivery', callback_data: 'FULFILL|DELIVERY' }],
    ...baseRows
  ];
} else {
  // delivery
  if (address) {
    keyboard = [
      [{ text: '💳 Pay now', callback_data: 'PAY' }],
      [{ text: 'Change to Pickup', callback_data: 'FULFILL|PICKUP' }],
      ...baseRows
    ];
  } else {
    keyboard = [
      [{ text: '📍 Add address', callback_data: 'ADDR|CHANGE' }],
      [{ text: 'Change to Pickup', callback_data: 'FULFILL|PICKUP' }],
      ...baseRows
    ];
  }
}

return [{
  json: {
    method: 'sendMessage',
    payload: {
      chat_id,
      text,
      parse_mode: 'Markdown',
      reply_markup: { inline_keyboard: keyboard }
    }
  }
}];

// Needs Phone? — fire ONLY on text messages while awaiting phone
const evt = $items('Normalize Event')[0].json;   // has chat_id, text, is_callback
const chat_id = String(evt.chat_id || '');
const rows = $items().map(i => i.json);          // from GS: Read State (phone)

// 1) Ignore button taps/callbacks entirely
if (evt.is_callback === true) return [];

// 2) Must be a non-empty text message
const text = typeof evt.text === 'string' ? evt.text.trim() : '';
if (!text) return [];

// 3) Find this user's state row
const row = rows.find(r => String(r.chat_id || r.ChatID) === chat_id);
if (!row) return []; // no state row yet

// 4) Only when we are truly waiting for phone
const fulfillment = String(row.Fulfillment || '').toLowerCase();
const step        = String(row.CurrentStep || '').toLowerCase();
const isPickupOrDelivery = (fulfillment === 'pickup' || fulfillment === 'delivery');

const needsPhone = isPickupOrDelivery && step === 'await_phone';

// 5) Pass row + the text we just received forward
return needsPhone ? [{
  json: {
    ...row,
    _chat_id: chat_id,
    _text: text
  }
}] : [];

// Validate Ghana Phone — preserve incoming fields
const chat_id = $json._chat_id || $json.chat_id;
const raw = String($json._text || $json.text || '').replace(/\s+/g, '');

function normGhana(n) {
  if (/^\+?233\d{9}$/.test(n)) {
    const tail = n.replace(/^\+?233/, '');
    return { e164: '+233' + tail, local: '0' + tail };
  }
  if (/^0\d{9}$/.test(n)) {
    return { e164: '+233' + n.slice(1), local: n };
  }
  return null;
}

const norm = normGhana(raw);

return [{
  json: {
    ...$json,                  // << keep Fulfillment, CurrentStep, etc.
    chat_id,
    valid: !!norm,
    phone_local: norm?.local || '',
    phone_e164: norm?.e164 || ''
  }
}];

// Reply: Invalid Phone — do NOT reference other nodes by name
const chat_id = $json._chat_id || $json.chat_id;

const hint =
  '⚠️ *That phone number looks invalid.*\n' +
