    }
  }
}];

const now = new Date().toISOString();
$json._prevStep   = $json.CurrentStep || '';
$json.Fulfillment = 'delivery';

// Only move to await_phone if phone missing
const phone = String($json.phone || $json.Phone || '').trim();
if (!phone) $json.CurrentStep = 'await_phone';

$json.UpdatedAt = now;
return [$json];

// Try current item first (from After Update), then fall back safely.
const chat_id =
  $json.chat_id ??
