}];

// Has State? — always runs because it receives an item from Ack? (safe)1.
// It inspects the parallel GS read results to decide whether a row exists.

const chatId = String(
  $json.chat_id ??
  $items('Parse Callback')[0]?.json?.chat_id ?? ''
);

// Use the exact node name as it appears in your left panel: GS: Read State(delivery)
const rows = ($items('GS: Read State(delivery)') || []).map(i => i.json);
const hit  = rows.find(r => String(r.chat_id) === chatId) || null;

return [{
