/** Fire only on text when the user should provide an address. */
const rows = ($items('GS: Read State (phone)') || []).map(i => i.json);
const evt  = $items('Normalize Event')[0]?.json || {};
if (evt.is_callback) return [];

const chat_id = evt.chat_id;
const text    = (evt.text || '').trim();
if (!text) return [];

// NEW: ignore if message looks like a phone number (0XXXXXXXXX or +233XXXXXXXXX)
const digits = text.replace(/\s+/g, '');
if (/^(0\d{9}|\+?233\d{9})$/.test(digits)) return [];

const row = rows.find(r => String(r.chat_id) === String(chat_id));
if (!row) return [];

const fulfillment = (row.Fulfillment || '').toLowerCase().trim();
const step        = (row.CurrentStep || '').toLowerCase().trim();

const needsAddr = (fulfillment === 'delivery') && (step === 'await_addr');
return needsAddr ? [{ json: { chat_id, address_text: text } }] : [];

// Inputs
const chat_id = String($json.chat_id ?? '');
const address_raw = String($json.address_text ?? '').trim();
const address = address_raw.toLowerCase();

// Zones table from GS: Read Zones (5 items in your run)
const rows = ($items('GS: Read Zones') || []).map(i => i.json);

// Build "available" (only those marked true)
const available = rows
  .filter(r => String(r.Available).toLowerCase() === 'true')
  .map(r => String(r.ZoneName || '').trim())
  .filter(Boolean);

// Find first matching zone by keyword (case-insensitive; comma-separated tokens supported)
let hit = null;
for (const r of rows) {
  const kw = String(r.Keyword || '').toLowerCase();
  if (!kw) continue;
  const tokens = kw.split(',').map(s => s.trim()).filter(Boolean);
  if (tokens.some(t => address.includes(t))) {
    hit = r;
    break;
  }
}

// Always return an array of ONE object
if (hit) {
  return [{
    json: {
      chat_id,
      address_text: address_raw,
      found: true,
      Zone: String(hit.ZoneName || '').trim(),
      DeliveryFee: Number(hit.DeliveryFee || 0),
      available,
    }
  }];
} else {
  return [{
    json: {
      chat_id,
      address_text: address_raw,
      found: false,
      available,
    }
  }];
}

// Reply: Address OK  — returns a Telegram sendMessage payload

const chat_id = $json.chat_id;

// Safe reads with sensible fallbacks
const address = String($json.Address ?? '').trim();
const zone    = String($json.Zone ?? '').trim();

// Fee: number or string -> pretty, or fallback
const rawFee  = $json.DeliveryFee;
const feeNum  = (rawFee === '' || rawFee === null || rawFee === undefined)
  ? null
  : Number(rawFee);
const feeText = (feeNum !== null && !Number.isNaN(feeNum)) ? `₵${feeNum}` : 'to be confirmed';

// Message
const text = [
  '📍 *Address saved*',
  '',
  `*Address:* ${address || '—'}`,
  `*Zone:* ${zone || '—'}`,
  `*Delivery fee:* ${feeText}`,
  '',
  'Use the buttons below, or type a new address to change it.'
].join('\n');

// Inline buttons with unique callback_data
const reply_markup = {
