// filter Cart — keep ONLY active, unpaid, unfrozen lines for THIS user (qty > 0)

// get current chat_id from Parse Callback (or current item)
const ctx = $items('Parse Callback')?.[0]?.json ?? {};
const chat_id = String(ctx.chat_id ?? $json.chat_id ?? '');

// helpers
const asInt = (v, d = 0) => {
  const n = Number(v);
  return Number.isFinite(n) ? n : d;
};
const isTrue = (v) => ['true','1','yes'].includes(String(v ?? '').trim().toLowerCase());
const isPaid = (v) => ['paid','success','successful','confirmed','complete','completed','true','yes','1']
  .includes(String(v ?? '').trim().toLowerCase());

// source rows from GS: Read Cart (previous node)
const rows = $input.all().map(i => i.json);

// apply filters
const active = rows.filter(r => {
  if (!r || !r.SKU) return false;                  // must be a cart line
  if (String(r.chat_id ?? '') !== chat_id) return false; // this user only
  if (asInt(r.Quantity, 0) <= 0) return false;     // qty > 0
  if (isTrue(r.Frozen)) return false;              // drop frozen
  if (isPaid(r.PaymentStatus)) return false;       // drop paid
  return true;
});

// emit same shape items for downstream nodes
return active.map(r => ({ json: r }));

/**
 * Build a pre-payment checkout summary (Markdown) in user's existing style.
 * Accepts cart rows and one state row in ANY order.
 * Expects columns in cart: Dish, SKU, Price, Quantity, LineTotal
 * Expects state: Fulfillment, Zone, DeliveryFee
 */

const CURRENCY = '¢'; // keep your Ghana cedi symbol formatting
const HEADER = '🧾 *Checkout*';
const EMPTY = 'Your cart is empty.\n\nTap *Menu* to add items.';

// ---- helpers ----
const clean = v => (v ?? '').toString().trim();
const num = v => {
  const n = parseFloat(v);
  return Number.isFinite(n) ? n : 0;
};
const money = v => `${CURRENCY}${(Math.round(num(v) * 100) / 100).toString()}`;

// ---- collect inputs (cart + state) in any order ----
let cart = [];
let state = {};

for (const item of $input.all()) {
  const j = item.json || {};
  // Heuristic: state row usually has Fulfillment and Zone fields
  if ('Fulfillment' in j || 'Zone' in j || 'DeliveryFee' in j) {
    // choose the first non-empty state row
    if (!state.chat_id && j.chat_id) state = j;
  } else {
    cart.push(j);
  }
}

// If the state read returned an array (some n8n versions), normalize:
if (Array.isArray(state) && state.length) state = state[0];

// Fallback to any upstream chat id
const chat_id = $json.chat_id
  ?? state.chat_id
  ?? $items(0)[0]?.json?.chat_id
  ?? $items(1)[0]?.json?.chat_id;

// ---- compute sums ----
let lines = [];
let subtotal = 0;

for (const row of cart) {
  const dish = clean(row.Dish || row.Item || row.Name);
  const qty  = num(row.Quantity);
  const price = num(row.Price);
  const line = num(row.LineTotal) || qty * price;

  if (!dish || qty <= 0) continue;

  subtotal += line;
  lines.push(`• ${dish}  x${qty}  —  ${money(line)}`);
}

const hasItems = lines.length > 0;

// delivery context
const fulfillment = clean(state.Fulfillment).toLowerCase(); // 'delivery' | 'pickup'
const zone = clean(state.Zone);
const deliveryFee = num(state.DeliveryFee);
const isDelivery = fulfillment === 'delivery';

const feeLine =
  isDelivery
    ? (deliveryFee > 0
        ? `\nDelivery fee (${zone || '—'}): *${money(deliveryFee)}*`
        : `\nDelivery fee: *—*`)
    : '';

const total = subtotal + (isDelivery ? deliveryFee : 0);

// ---- message text ----
let text;
if (!hasItems) {
  text = EMPTY;
} else {
  text =
    `${HEADER}\n\n` +
    `${lines.join('\n')}\n\n` +
    `Subtotal: *${money(subtotal)}*` +
    `${feeLine}` +
    `\nTotal: *${money(total)}*` +
    `\n\nFulfillment: *${fulfillment || '—'}*` +
    (isDelivery && !zone ? `\nZone: *—* (tap “✏️ Change address”)` : '');
}

// ---- inline keyboard (keep your existing callback styles) ----
const keyboard = hasItems
  ? [
      [
        { text: '✅ Proceed to pay', callback_data: 'PAY|INSTR' }
      ],
      [
        { text: '✏️ Change address', callback_data: 'ADDR|CHANGE' },
        { text: '🚗 Change to Pickup', callback_data: 'FULFILL|PICKUP' }
      ],
      [
        { text: '🧹 Clear cart', callback_data: 'CART|CLEAR' },
        { text: '📜 Menu', callback_data: 'MENU' }
      ]
    ]
  : [
      [
        { text: '📜 Menu', callback_data: 'MENU' }
      ]
    ];

// ---- emit Telegram payload ----
return [{
  json: {
    method: 'sendMessage',
    payload: {
      chat_id,
      text,
      parse_mode: 'Markdown',
      reply_markup: { inline_keyboard: keyboard }
    }
  }
}];

// Expect input items from "Join: Cart + OrderNo" (one per cart row)
// Each should have row_number and OrderNumber
const out = [];
for (const it of $input.all()) {
  const j = it.json || {};
  if (j.row_number != null && j.OrderNumber) {
    out.push({ json: { row_number: j.row_number, OrderNumber: j.OrderNumber } });
  }
}
// If nothing matched, don't break downstream—just emit nothing
return out;

// Build Payment Instructions (with PAYMENT_MODE)
// Buttons & copy adapt to env: BOTH | MOMO_ONLY | MANUAL_ONLY

const modeRaw = String($env.PAYMENT_MODE || 'BOTH').toUpperCase();
const MODE = ['BOTH','MOMO_ONLY','MANUAL_ONLY'].includes(modeRaw) ? modeRaw : 'BOTH';

const BrandName   = String($env.BRAND_NAME   || 'Sefake Kitchen');
const MomoName    = String($env.MOMO_NAME    || 'Sefake Kitchen');
const MomoNumber  = String($env.MOMO_NUMBER  || '0241234567');
const MomoNetwork = String($env.MOMO_NETWORK || 'MTN');

const BACK_CB = 'CART|CHECKOUT';

// helpers
const num = (v, d=0) => { const n = Number(String(v ?? '').replace(/[, ]/g,'')); return Number.isFinite(n)?n:d; };
const money = v => `₵${Number(v).toLocaleString('en-GH',{minimumFractionDigits:2,maximumFractionDigits:2})}`;
const safe = s => (s==null?'':String(s).trim());

// inputs → split cart vs state
let cart=[], order={};
for (const it of items.map(i=>i.json)) {
  const isCart = !!(it.SKU || it.Dish || it.Item || it.Name);
  const isState= ('Fulfillment' in it) || ('DeliveryFee' in it) || ('Zone' in it) || ('chat_id' in it);
  if (isCart) {
    cart.push(it);
    if (!order.OrderNumber && it.OrderNumber) order.OrderNumber = safe(it.OrderNumber);
    if (!order.chat_id && it.chat_id) order.chat_id = it.chat_id;
  } else if (isState) {
    order = { ...order, ...it };
    if (!order.OrderNumber && it.OrderNumber) order.OrderNumber = safe(it.OrderNumber);
  }
}

// totals
let subtotal=0;
for (const line of cart) {
  const lt=num(line.LineTotal), p=num(line.Price), q=num(line.Quantity,1);
  subtotal += (Number.isFinite(lt)&&lt>0) ? lt : p*q;
}
const deliveryFee = num(order.DeliveryFee,0);
const total = subtotal + deliveryFee;

// ref & chat
const ref = safe(order.OrderNumber || order.OrderUID || order.OrderId || '');
const chat_id = order.chat_id || order.ChatID || order.chatid || order.user_id;

// message
const head = '💳 *Payment for Order*' + (ref ? `\nRef: *${ref}*` : '');
const breakdown = [
  `Subtotal: *${money(subtotal)}*`,
  ...(deliveryFee>0 ? [`Delivery fee: *${money(deliveryFee)}*`] : []),
].join('\n');
const totalPanel = ['━━━━━━━━━━━━━━━━━━━━', `💥 *TOTAL TO PAY: ${money(total)}*`, '━━━━━━━━━━━━━━━━━━━━'].join('\n');

const lines = [];
lines.push(head,'',breakdown,totalPanel,'');

// choice-specific copy
if (MODE === 'BOTH') {
  lines.push('You can either:');
  lines.push('• Tap *MoMo Pay now* for instant approval, or');
  lines.push('• Pay manually and tap *I have paid* (admin will verify).','');
} else if (MODE === 'MOMO_ONLY') {
  lines.push('Please pay via *MoMo Pay now*. Approval is instant.','');
} else { // MANUAL_ONLY
  lines.push('Please complete a manual transfer, then tap *I have paid* for admin verification.','');
}

// show manual MoMo details only if manual path is available
if (MODE !== 'MOMO_ONLY') {
  lines.push('🟡 *Very important*');
  if (ref) { lines.push('Use this in the *Reference/Reason/Message* field:', `🧾 *${ref}*`); }
  lines.push('This helps us match your payment quickly.','');
  lines.push('📲 *Manual MoMo Details*');
  lines.push(`• Network: ${MomoNetwork}`);
  lines.push(`• Number: ${MomoNumber}`);
  lines.push(`• Name: ${MomoName}`,'');
}

lines.push('Tap the button below to continue.');
const text = lines.join('\n');

// buttons (conditionally include)
const kb = [];
if (MODE !== 'MOMO_ONLY') {
  kb.push([{ text: '✅ I have paid', callback_data: `PAY|CONFIRM|${ref || 'UNKNOWN'}` }]);
}
if (MODE !== 'MANUAL_ONLY') {
  kb.push([{ text: '💳 MoMo Pay now', callback_data: `PAY|MOMO|${ref || 'UNKNOWN'}` }]);
}
kb.push([{ text: '⬅️ Back to checkout', callback_data: BACK_CB }]);

return [{
