      text: msg,
      show_alert: true
    }
  };
}

return [{ json: out }];

// Collect all upstream items (from UserStates + Cart)
const rows = $input.all().map(i => i.json);

// ---- env & helpers ----
const CC        = ($env.MOMO_MSISDN_CC || '233').replace(/\D/g, '');   // default Ghana
const BRAND     = $env.BRAND_NAME || 'Sefake Kitchen';
const CURRENCY  = String($env.MOMO_CURRENCY || 'EUR').toUpperCase();

const asNum = v => {
  const n = parseFloat(String(v ?? '').replace(/[, ]/g, ''));
  return Number.isFinite(n) ? n : 0;
};

// CC-aware MSISDN normalizer
const normMsisdn = p => {
  const s = String(p ?? '').replace(/\D/g, '');
  if (!s) return '';                                   // handle missing
  if (s.startsWith('0'))   return CC + s.slice(1);
  if (s.startsWith(CC))    return s;
  return CC + s;                                       // best-effort
};

// ---- split state vs cart ----
let state = {};
let cart  = [];
for (const r of rows) {
  const looksState = ('DeliveryFee' in r) || ('LastOrderNumber' in r) || ('Fulfillment' in r);
  const looksCart  = ('SKU' in r) || ('Dish' in r) || ('Price' in r) || ('Quantity' in r) || ('LineTotal' in r);
  if (looksState) state = { ...state, ...r };
  else if (looksCart) cart.push(r);
}

// ---- totals ----
let subtotal = 0;
for (const li of cart) {
  const lt = asNum(li.LineTotal);
  const p  = asNum(li.Price);
  const q  = asNum(li.Quantity || 1);
  subtotal += (lt > 0 ? lt : (p * q));
}
const deliveryFee = asNum(state.DeliveryFee);
const total = Math.round((subtotal + deliveryFee) * 100) / 100;

// ---- reference, chat, payer ----
const externalId = String(state.LastOrderNumber || state.LastOrderUID || state.OrderNumber || '').trim();
const chat_id    = state.chat_id || state.ChatID || state.chatid || state.user_id || '';
const payerId    = normMsisdn(state.Phone);

// ---- guard rails (fail fast with a clear message) ----
if (!externalId) throw new Error('MoMo: Missing reference (LastOrderNumber) in UserStates.');
if (!payerId || payerId.length < (CC.length + 7)) throw new Error('MoMo: Missing/invalid Phone in UserStates.');
if (total <= 0) throw new Error('MoMo: Total is 0; nothing to charge.');

// ---- payload for RequestToPay ----
return [{
  json: {
    chat_id,
    externalId,                  // <- expose directly (simplifies HTTP node)
    amount: total.toFixed(2),    // string, 2dp
    currency: CURRENCY,          // env-driven: EUR in sandbox, GHS in prod
    payer: { partyIdType: 'MSISDN', partyId: payerId },
    payerMessage: `${BRAND} ${externalId}`,
    payeeNote: `Order ${externalId}`,

    // extras for logs/analytics
    ref: externalId,
    subtotal,
    deliveryFee,
    lineCount: cart.length
  }
}];

function uuidv4() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random()*16|0, v = c === 'x' ? r : (r&0x3|0x8);
    return v.toString(16);
  });
}
return [{ json: { rtpRef: uuidv4() } }];

