/**
 * Build Kitchen Ticket — robust merge + direct state fallback
 */

const C = '₵';
const clean = v => (v ?? '').toString().trim();
const num = v => { const n = Number(v); return Number.isFinite(n) ? n : 0; };
const money = v => `${C}${num(v).toFixed(2)}`;
const md = s => String(s ?? '').replace(/([_*\[\]()~`>#+\-=|{}.!])/g, '\\$1');

// All inputs from Merge: State + Cart (ticket)
const items = $input.all().map(i => i.json);

// Try find state row inside the merge
let state = items.find(r =>
  (!r.SKU && !r.Dish) &&
  (r.Fulfillment || r.Phone || r.Address || r.Zone || r.DeliveryFee || r.chat_id || r.PaymentMethod)
) || {};

// If not found, hard-pull from the node (index 0)
try {
  const s0 = $node['GS: Get UserState (fresh)']?.json || {};
  if (Object.keys(state).length === 0 && Object.keys(s0).length) state = s0;
} catch (_) { /* ignore */ }

// Build a safe getter over `state`
const stateGet = k => {
  const v = state[k] ?? state[k?.toLowerCase?.()] ?? state[k?.toUpperCase?.()];
  return v == null ? '' : v;
};

// Derive chat_id with multiple fallbacks (state → any cart row → Poll Vars)
const chat_id =
  clean(stateGet('chat_id')) ||
  clean((items.find(r => r.chat_id)?.chat_id) ?? '') ||
  clean($node['Set: Poll Vars']?.json?.chat_id ?? '');

// Order reference from several places
const ref =
  clean(stateGet('OrderNumber')) ||
  clean($json.ref) ||
  clean(items.find(r => r.OrderNumber)?.OrderNumber ?? '') ||
  '—';

// Split cart rows (anything with SKU or Dish)
const cart = items.filter(r => (r.SKU || r.Dish));

// Build lines + subtotal
let subtotal = 0;
const orderLines = cart.map((r, idx) => {
  const qty   = num(r.Quantity);
  const price = num(r.Price);
  const line  = num(r.LineTotal || qty * price);
  subtotal += line;
  return {
    Timestamp: clean(r.Timestamp || new Date().toISOString()),
    OrderNumber: ref,
    chat_id,                                 // <- now filled
    SKU: clean(r.SKU || ''),
    Dish: clean(r.Dish || ''),
    Quantity: qty,
    Price: price,
    LineTotal: line,
    _i: idx
  };
}).sort((a,b)=>a._i-b._i).map(({_i, ...x}) => x);

// Totals + header row
const deliveryFee = num(stateGet('DeliveryFee'));
const total = subtotal + deliveryFee;

const orderRow = {
  Timestamp: new Date().toISOString(),
  OrderNumber: ref,
  chat_id,
  Fulfillment: clean(stateGet('Fulfillment')),
  Phone: clean(stateGet('Phone')),
  Address: clean(stateGet('Address')),
  Zone: clean(stateGet('Zone')),
  DeliveryFee: deliveryFee,
  Subtotal: subtotal,
  Total: total,
  PaymentStatus: 'PAID',
  PaymentMethod: clean(stateGet('PaymentMethod')) || 'MOMO'
};

// Human ticket
const ticket = [
  '*NEW ORDER*',
  `*${ref}* Paid via ${orderRow.PaymentMethod} ✅`,
  '',
  ...orderLines.map(l => `${md(l.Dish)} x${l.Quantity} — ${money(l.LineTotal)}`),
  '',
  `Subtotal: *${money(subtotal)}*`,
  `Delivery: *${money(deliveryFee)}*`,
  `Total: *${money(total)}*`,
  '',
  `Fulfillment: *${md(orderRow.Fulfillment || '—')}*`,
  `Phone: *${md(orderRow.Phone || '—')}*`,
  `Address: *${md(orderRow.Address || '—')}*`,
  `Zone: *${md(orderRow.Zone || '—')}*`
].join('\n');

return [{ json: { ticket, orderRow, orderLines, ref } }];

