// Pass-through guard: never return []
const items = $input.all();
return items.length ? items : [{ json: { ok: true } }];

/**
 * Build Daily Summary (Cart-only) — resilient target + no-empty output
 * - Filters to *today*, keeps only PAID rows with an OrderNumber
 * - Metrics: Orders, Items Sold, Gross Sales, AOV, Top 5 items
 * - Target chat resolution:
 *      1) REPORT_TARGET_ID || OWNER_CHAT_ID || ADMIN_CHAT_ID (if available)
 *      2) else first chat_id found in sheet rows (fallback)
 * - Always outputs a sendMessage payload (no silent [] returns)
 */

const CURRENCY = '₵';
const TZ = 'Africa/Accra'; // adjust if you prefer; safe default for you

// --- helpers ---
const md = s => String(s ?? '').replace(/([_*\[\]()~`>#+\-=|{}.!])/g, '\\$1');
const num = v => {
  if (typeof v === 'number') return Number.isFinite(v) ? v : 0;
  const s = String(v ?? '').replace(/[^\d.\-]/g, '');
  const n = parseFloat(s);
  return Number.isFinite(n) ? n : 0;
};
const asInt = v => Math.round(num(v));
const money = v => `${CURRENCY}${num(v).toFixed(2)}`;
const isPaid = s => {
  const t = String(s ?? '').toLowerCase().trim();
  return ['paid','pay','success','successful','confirmed','complete','completed','true','yes','1'].includes(t);
};

// --- collect rows from GS: Read Cart (ALL) ---
const rows = $input.all().map(i => i.json);

// --- derive target chat id ---
let REPORT_TARGET_ID = '';
let OWNER_CHAT_ID = '';
let ADMIN_CHAT_ID = '';
try {
  if (typeof process !== 'undefined' && process.env) {
    REPORT_TARGET_ID = String(process.env.REPORT_TARGET_ID || '').trim();
    OWNER_CHAT_ID    = String(process.env.OWNER_CHAT_ID    || '').trim();
    ADMIN_CHAT_ID    = String(process.env.ADMIN_CHAT_ID    || '').trim();
  }
} catch (_) { /* sandbox without process.env */ }

// Fallback to a chat_id present in the rows (quick win for testing)
const rowChat = String((rows.find(r => r.chat_id) || {}).chat_id || '').trim();

// Final target
const TARGET_CHAT_ID = REPORT_TARGET_ID || OWNER_CHAT_ID || ADMIN_CHAT_ID || rowChat;

// If absolutely nothing, fail loud (so you notice) instead of silent []
if (!TARGET_CHAT_ID) {
  return [{
    json: {
      method: 'sendMessage',
      payload: {
        chat_id: rowChat || '0',
        text: '⚠️ Analytics report could not pick a target chat. Set REPORT_TARGET_ID or OWNER_CHAT_ID/ADMIN_CHAT_ID.',
        parse_mode: 'Markdown'
      }
    }
  }];
}

// --- date helpers (today in TZ) ---
const nowTZ = new Date(new Date().toLocaleString('en-US', { timeZone: TZ }));
const y = nowTZ.getFullYear();
const m = nowTZ.getMonth() + 1;
const d = nowTZ.getDate();
const pad = n => (n < 10 ? '0' + n : '' + n);
const todayStr = `${y}-${pad(m)}-${pad(d)}`;
const niceDate = nowTZ.toLocaleDateString('en-GB', { day:'2-digit', month:'short', year:'numeric', timeZone: TZ });

// --- filter to today + paid + has OrderNumber ---
const todayPaid = [];
for (const r of rows) {
  const ts = r.Timestamp ?? r.timestamp ?? r.Date ?? r.date;
  const day = ts ? new Date(ts).toLocaleDateString('en-CA', { timeZone: TZ }) : '';
  const hasRef = !!String(r.OrderNumber ?? r.Ref ?? r.Reference ?? '').trim();
  if (day === todayStr && hasRef && isPaid(r.PaymentStatus ?? r.Status ?? r.status)) {
    todayPaid.push(r);
  }
}

// --- aggregate ---
const orderRefs = new Set();
let gross = 0;
let items = 0;
const byItem = new Map();

for (const r of todayPaid) {
  const ref = String(r.OrderNumber ?? r.Ref ?? r.Reference ?? '').trim();
  if (ref) orderRefs.add(ref);
  gross += num(r.LineTotal ?? r.Total ?? r.Line_Amount);
  const q = num(r.Quantity ?? r.Qty ?? 1);
  items += q;
  const key = String(r.Dish ?? r.Item ?? r.SKU ?? 'Unknown').trim();
  byItem.set(key, (byItem.get(key) || 0) + q);
}

const orders = orderRefs.size;
const aov = orders ? gross / orders : 0;

// --- top items ---
const top = Array.from(byItem.entries()).sort((a,b)=>b[1]-a[1]).slice(0,5);

// --- build message ---
let lines = [];
lines.push(`📈 *Daily Report — ${md(niceDate)}*`);
if (!orders) {
  lines.push('', 'No *paid* orders yet today.');
} else {
  lines.push('');
  lines.push(`• Orders: *${orders}*`);
  lines.push(`• Items sold: *${asInt(items)}*`);
  lines.push(`• Gross sales: *${money(gross)}*`);
  lines.push(`• AOV: *${money(aov)}*`);
  if (top.length) {
    lines.push('', '*Top items:*');
    let rank = 1;
    for (const [name, qty] of top) {
      lines.push(`${rank}. ${md(name)} — *${asInt(qty)}*`);
      rank++;
    }
  }
}
const text = lines.join('\n');

// --- output for TG: Send or Edit ---
return [{
  json: {
    method: 'sendMessage',
    payload: {
      chat_id: TARGET_CHAT_ID,
      text,
      parse_mode: 'Markdown',
      disable_web_page_preview: true
    }
  }
}];

return [{
  json: {
    chat_id: $node['Extract PAY|CONFIRM Ref'].json.chat_id,
    text: `We already processed order *${$node['Extract PAY|CONFIRM Ref'].json.ref}*. If you think there's an issue, reply here.`,
    parse_mode: "Markdown"
  }
}];

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  item.json.myNewField = 1;
}

return $input.all();

