parameters.jsCode:
// Take either HTTP body or raw JSON and normalize status for the Switch
const body = $json.body ?? $json;
const s0 = String(body.status ?? body.Status ?? '').toUpperCase().trim();
const map = { SUCCESS: 'SUCCESSFUL' };                 // MTN sometimes returns SUCCESS
const known = ['SUCCESSFUL', 'FAILED', 'REJECTED', 'PENDING'];

let status = map[s0] || s0;

// If nothing useful came back (404/empty), treat as PENDING to keep polling
if (!status) status = 'PENDING';
else if (!known.includes(status)) status = 'UNKNOWN';

const httpStatus = $json.statusCode ?? $json.code ?? null;
return [{ json: { ...body, status, httpStatus } }];
